import{_ as o,o as d,c,ag as i}from"./chunks/framework.BZohXCq9.js";const h=JSON.parse('{"title":"API 快速索引","description":"","frontmatter":{},"headers":[],"relativePath":"api.md","filePath":"api.md","lastUpdated":1774528492000}'),l={name:"api.md"};function r(a,e,t,p,s,n){return d(),c("div",null,[...e[0]||(e[0]=[i('<h1 id="api-快速索引" tabindex="-1">API 快速索引 <a class="header-anchor" href="#api-快速索引" aria-label="Permalink to &quot;API 快速索引&quot;">​</a></h1><p>这个页面主要作为 API 入口和 SDK 对象速查表。</p><p>如果目标是安装和运行宿主应用，建议先看 <a href="/install">安装与发布</a>；如果目标是开发 driver，建议先看 <a href="/sdk">SDK 开发者指南</a>。</p><p>如果目标已经比较明确，可以直接从这里跳到对应类型或对应包的 API 页面；如果只是想先看“接一个 driver 到底要碰哪些对象”，建议先读下面这部分。</p><h2 id="完整-api-参考" tabindex="-1">完整 API 参考 <a class="header-anchor" href="#完整-api-参考" aria-label="Permalink to &quot;完整 API 参考&quot;">​</a></h2><p>从源码 docstring 自动生成的 API 文档入口如下：</p><ul><li><a href="./pdoc/index.html">打开 pdoc 总览</a></li></ul><p>各个主要包的入口如下：</p><ul><li><a href="./pdoc/modlink_sdk.html">modlink_sdk</a></li><li><a href="./pdoc/modlink_core.html">modlink_core</a></li><li><a href="./pdoc/modlink_ui.html">modlink_ui</a></li><li><a href="./pdoc/modlink_studio.html">modlink_studio</a></li></ul><p>如果这些链接出现 404，通常说明文档站或 pdoc 产物还没有重新构建。</p><h2 id="先建立一条最小接入链路" tabindex="-1">先建立一条最小接入链路 <a class="header-anchor" href="#先建立一条最小接入链路" aria-label="Permalink to &quot;先建立一条最小接入链路&quot;">​</a></h2><p>从 SDK 视角看，一个 driver 的最小工作链路通常是：</p><ol><li>宿主创建一个 <code>Driver</code> 或 <code>LoopDriver</code> 实例</li><li>宿主调用 <code>descriptors()</code>，读取这个 driver 会暴露哪些 <code>StreamDescriptor</code></li><li>宿主调用 <code>search()</code>，拿到一组 <code>SearchResult</code></li><li>宿主把选中的 <code>SearchResult</code> 传回 <code>connect_device()</code></li><li>driver 开始流并提供实时数据后，通过 <code>sig_frame</code> 发出 <code>FrameEnvelope</code></li><li>每个 <code>FrameEnvelope</code> 都必须能够对应到前面声明过的某个 <code>StreamDescriptor</code></li></ol><p>如果这条链路里有一环没有定义清楚，宿主、录制和 UI 就很难稳定工作。因此更需要优先明确的不是“页面长什么样”，而是：</p><ul><li>这个 driver 有哪些 stream</li><li>每个 stream 的 <code>payload_type</code> 是什么</li><li>每次发出的 <code>FrameEnvelope.data</code> shape 应该怎么解释</li></ul><h2 id="sdk-里最常看的对象" tabindex="-1">SDK 里最常看的对象 <a class="header-anchor" href="#sdk-里最常看的对象" aria-label="Permalink to &quot;SDK 里最常看的对象&quot;">​</a></h2><h3 id="driver" tabindex="-1"><code>Driver</code> <a class="header-anchor" href="#driver" aria-label="Permalink to &quot;`Driver`&quot;">​</a></h3><p><code>Driver</code> 是所有 driver 的根基类，也是最保守、最通用的起点。</p><p>它定义的不是某种具体采集方式，而是一套宿主能理解的统一生命周期：</p><ul><li><code>descriptors()</code>：声明这个 driver 会发哪些流</li><li><code>search()</code>：发现可连接的候选设备</li><li><code>connect_device()</code> / <code>disconnect_device()</code>：建立和释放连接</li><li><code>start_streaming()</code> / <code>stop_streaming()</code>：开始和停止实时数据流</li><li><code>sig_frame</code>：把 <code>FrameEnvelope</code> 发给宿主</li></ul><p>适合直接继承 <code>Driver</code> 的情况：</p><ul><li>设备 SDK 本身是 callback 型</li><li>第三方库会自己推数据过来</li><li>采集逻辑不适合表达成一个固定频率的短轮询</li><li>你暂时还不确定轮询模型是否真的合适</li></ul><p>如果暂时无法判断，默认回到 <code>Driver</code>。<code>Driver</code> 的抽象更直接，也更不容易把设备本身的逻辑勉强套进并不合适的轮询模型里。</p><h3 id="loopdriver" tabindex="-1"><code>LoopDriver</code> <a class="header-anchor" href="#loopdriver" aria-label="Permalink to &quot;`LoopDriver`&quot;">​</a></h3><p><code>LoopDriver</code> 的基类也是 <code>Driver</code>。它不是另一套独立协议，只是在 <code>Driver</code> 之上，为“需要轮询获取数据”的那类设备封装了一个现成的 helper。</p><p>它主要帮你做了两件事：</p><ul><li>把 <code>start_streaming()</code> / <code>stop_streaming()</code> 包装成基于 <code>QTimer</code> 的循环</li><li>给你一个 <code>loop()</code> 钩子，让你只需要写“一次短轮询里做什么”</li></ul><p>通常子类只需要：</p><ul><li>像普通 <code>Driver</code> 一样实现 <code>descriptors()</code>、<code>search()</code>、<code>connect_device()</code>、<code>disconnect_device()</code></li><li>实现 <code>loop()</code></li><li>按需调整 <code>loop_interval_ms</code></li><li>按需实现 <code>on_loop_started()</code> / <code>on_loop_stopped()</code></li></ul><p>适合使用 <code>LoopDriver</code> 的情况：</p><ul><li>串口轮询</li><li>BrainFlow 风格设备</li><li>一次短循环就能表达清楚的采集逻辑</li><li>“检查是否有新数据，再取出并发帧” 这一类模式</li></ul><p>不适合的情况也需要明确：</p><ul><li>回调型 SDK</li><li>单次调用会长时间阻塞的读取逻辑</li><li>需要复杂状态机才能驱动的采集流程</li></ul><p>还不确定时，优先回到 <code>Driver</code>。<code>LoopDriver</code> 是对轮询型设备的便利封装，不是所有 driver 都该往这个模型上靠。</p><h3 id="searchresult" tabindex="-1"><code>SearchResult</code> <a class="header-anchor" href="#searchresult" aria-label="Permalink to &quot;`SearchResult`&quot;">​</a></h3><p><code>SearchResult</code> 是 <code>search()</code> 返回的候选设备对象。它的职责很具体：让宿主能展示搜索结果，并在用户选中后把必要配置原样带回 <code>connect_device()</code>。</p><p>最常用字段：</p><ul><li><code>title</code>：列表主标题</li><li><code>subtitle</code>：列表副标题</li><li><code>extra</code>：driver 自己定义的连接参数</li></ul><p>可选补充字段：</p><ul><li><code>device_id</code>：driver 提供的稳定设备标识</li></ul><p>这里最重要的边界是：宿主不会解析 <code>extra</code> 的内部结构。它只负责展示 <code>title</code> / <code>subtitle</code>，然后把整个 <code>SearchResult</code> 回传给 <code>connect_device()</code>。因此你可以把端口号、地址、序列号、传输参数等信息放进 <code>extra</code>，由 driver 自己消费。<code>device_id</code> 也不是宿主当前会消费的字段；它不是必填项，只有在 driver 希望额外提供设备标识时才需要提供。</p><h3 id="streamdescriptor" tabindex="-1"><code>StreamDescriptor</code> <a class="header-anchor" href="#streamdescriptor" aria-label="Permalink to &quot;`StreamDescriptor`&quot;">​</a></h3><p><code>StreamDescriptor</code> 描述的是“这个 driver 会发出什么流”，它是静态契约，不是实时数据。</p><p>宿主可能会在设备连接前就读取 <code>descriptors()</code>，所以 <code>StreamDescriptor</code> 里写的内容应该在 driver 生命周期内保持稳定。</p><p>写 <code>StreamDescriptor</code> 时，至少要把这几件事讲清楚：</p><ul><li><code>device_id</code>：这个流属于哪个设备实例，并参与 <code>stream_id</code> 派生</li><li><code>modality</code>：这是哪一类模态，并参与 <code>stream_id</code> 派生</li><li><code>payload_type</code>：只能从 <code>signal</code>、<code>raster</code>、<code>field</code>、<code>video</code> 中选择，它决定预览和录制链路如何解释 <code>FrameEnvelope.data</code></li><li><code>nominal_sample_rate_hz</code>：正数，决定名义采样率相关行为</li><li><code>chunk_size</code>：正整数，录制链路会校验它是否和实际 frame 一致；高采样率设备通常适合更大的 <code>chunk_size</code></li><li><code>channel_names</code>：通道标签；如果数量和实际通道数一致，预览与录制会直接使用</li><li><code>display_name</code>：界面显示名；缺失时通常回退到 <code>stream_id</code></li><li><code>metadata</code>：补充但稳定的说明信息；其中 <code>unit</code> 不和 <code>signal</code> 绑定，只要流本身有明确量纲就可以填写，它当前会进入录制元数据，并显示在预览摘要中</li></ul><p>还需要明确两个关系：</p><ul><li><code>stream_id</code> 不是手写的，而是由 <code>device_id + modality</code> 派生出来的稳定标识</li><li><code>FrameEnvelope</code> 的 <code>stream_id</code> 必须和这里声明过的某个流对应上</li></ul><p>如果从 SDK 接入角度只保留一个重点，那就是：<code>StreamDescriptor</code> 决定了宿主如何理解后续的实时数据。这个对象定义不清，后面的 UI、录制和调试都会变得混乱。</p><h3 id="frameenvelope" tabindex="-1"><code>FrameEnvelope</code> <a class="header-anchor" href="#frameenvelope" aria-label="Permalink to &quot;`FrameEnvelope`&quot;">​</a></h3><p><code>FrameEnvelope</code> 是 driver 在运行时真正发出的数据块。前面的 <code>StreamDescriptor</code> 负责“声明”，<code>FrameEnvelope</code> 负责“兑现”这个声明。</p><p>每次发帧时，最关键的是下面这些字段：</p><ul><li><code>device_id</code></li><li><code>modality</code></li><li><code>timestamp_ns</code></li><li><code>data</code></li><li><code>seq</code></li><li><code>extra</code></li></ul><p>其中有三个实际约束最重要：</p><ol><li><code>device_id + modality</code> 会派生出 <code>stream_id</code>，它必须能对应到某个 <code>StreamDescriptor</code></li><li><code>data</code> 的 shape 必须和该 <code>StreamDescriptor</code> 的约定一致</li><li><code>timestamp_ns</code> 应该由 driver 提供真实时间语义，而不是随意填一个占位值</li></ol><p>可以把它理解成一句话：<code>StreamDescriptor</code> 说明“我会发什么”，<code>FrameEnvelope</code> 说明“我现在真的发了这一块数据”。</p><h2 id="继续阅读的入口" tabindex="-1">继续阅读的入口 <a class="header-anchor" href="#继续阅读的入口" aria-label="Permalink to &quot;继续阅读的入口&quot;">​</a></h2><ul><li>想接设备：看 <a href="/sdk">SDK</a></li><li>想理解运行时：看 <a href="/core">Core</a></li><li>想做页面展示：看 <a href="/ui">UI</a></li><li>想知道应用入口怎么挂插件：看 <a href="/app">App</a></li></ul>',58)])])}const u=o(l,[["render",r]]);export{h as __pageData,u as default};
